import React from 'react';
import ProjectCard from '../components/ProjectCard';

const Home = ({ projects }) => {
  return (
    <main className="app-shell">
      <section className="section hero">
        <div>
          <p>Software Engineer • MERN Stack • Product-focused</p>
          <h1>Building fast, polished web experiences for modern products.</h1>
          <p>
            I design and develop elegant full-stack applications using MongoDB, Express, React, and Node.js. This portfolio highlights engineering work, product-led features, and real-world project design.
          </p>
        </div>
      </section>

      <section className="section">
        <h2>Featured Projects</h2>
        <div className="cards">
          {projects.length
            ? projects.map((project, index) => (
                <ProjectCard key={index} project={project} />
              ))
            : Array.from({ length: 2 }).map((_, index) => (
                <ProjectCard key={index} project={{ title: 'Loading…', description: 'Loading content', techStack: [], link: '#', github: '#' }} />
              ))}
        </div>
      </section>
    </main>
  );
};

export default Home;
